# terraform/modules/ai-agent-instance/main.tf
# This Terraform module is called by the portal's IaC engine when a developer
# provisions an agent instance through the UI or API.

variable "instance_name"  { type = string }
variable "agent_type_id"  { type = string }
variable "environment"    { type = string }
variable "region"         { type = string }
variable "config"         { type = map(string) }

locals {
  # Load the resource preset for this agent type from the catalog manifest.
  resource_preset = jsondecode(file("${path.module}/../../catalog/resource_presets.json"))
  preset          = local.resource_preset[var.config["resource_class"]]
}

resource "kubernetes_deployment" "agent" {
  metadata {
    name      = var.instance_name
    namespace = "ai-agents-${var.environment}"
    labels = {
      "ai-portal/agent-type"    = var.agent_type_id
      "ai-portal/instance-name" = var.instance_name
    }
  }
  spec {
    replicas = local.preset.min_replicas
    selector { match_labels = { app = var.instance_name } }
    template {
      metadata { labels = { app = var.instance_name } }
      spec {
        container {
          name  = "agent"
          image = "registry.internal.example.com/agents/${var.agent_type_id}:${var.config["version"]}"
          resources {
            limits   = { cpu = local.preset.cpu_limit,   memory = local.preset.memory_limit }
            requests = { cpu = local.preset.cpu_request, memory = local.preset.memory_request }
          }
          env_from { secret_ref { name = "ai-agent-credentials" } }
        }
      }
    }
  }
}

output "endpoint" { value = "https://${var.instance_name}.ai-agents.internal.example.com" }
